// Lookup by company name (case-insensitive partial match)
export function findCompanyCareerSite(companyName: string): CompanyCareerSite | undefined {
  const search = companyName.toLowerCase();
  return COMPANY_CAREER_SITES.find(
    (c) =>
      c.name.toLowerCase() === search ||
      c.name.toLowerCase().includes(search) ||
      search.includes(c.name.toLowerCase())
  );
}

// Get all career site URLs as a list of sources
export function getAllCareerSiteUrls(): string[] {
  return COMPANY_CAREER_SITES.map((c) => c.careerUrl);
}

// Get career sites filtered by category
export function getSitesByCategory(category: CompanyCareerSite["category"]): CompanyCareerSite[] {
  return COMPANY_CAREER_SITES.filter((c) => c.category === category);
}